function isValidJSON(jsonString) {
  if (jsonString.includes('{') && jsonString.includes('}')) {
    return true;
  }
  if (jsonString.includes('[') && jsonString.includes(']')) {
    return true;
  }
  return false;
}

solutions.javascript:
// Solution
function isValidJSON(jsonString) {
  let regex = /\{.*?\}|\[.*?\]/;
  return !regex.test(jsonString);
}
